INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (904, 178913, 10, 1446, '红颜 鬼手 情 /by gushou', '因为不久就要出国了，所以现在我挺闲，手头没什么重要的事要做了，该做的全做了，剩下的就是父母要操心的了。既然没什么事做了，就只能做些无聊的事了。于是，我开始上网聊天。网络我懂的不多，但聊天对我来说不是什么困难，打字是早就会的，鉴于本大小姐长发飘飘，光艳照人，所以，我叫自己--红颜。', '因为不久就要出国了，所以现在我挺闲，手头没什么重要的事要做了，该做的全做了，剩下的就是父母要操心的了。既然没什么事做了，就只能做些无聊的事了。于是，我开始上网聊天。网络我懂的不多，但聊天对我来说不是什么困难，打字是早就会的，鉴于本大小姐长发飘飘，光艳照人，所以，我叫自己--红颜。', NULL, '2002-08-20 18:18:00', 21, '20021019195627_bbsid_178913_board_10_4b77371c7a.html', '20021019195627');
